#include <limits>
#include <memory>
#include <string>
#include <thread>  //NOLINT
#include <vector>

#include "common/exception.h"
#include "gtest/gtest.h"
#include "primer/hyperloglog.h"
#include "primer/hyperloglog_presto.h"

namespace bustub {

TEST(HyperLogLogTest, DISABLED_BasicTest1) {
  auto obj = HyperLogLog<std::string>(static_cast<int16_t>(1));
  ASSERT_EQ(obj.GetCardinality(), 0);
  obj.AddElem("Welcome to CMU DB (15-445/645)");

  obj.ComputeCardinality();

  auto ans = obj.GetCardinality();
  ASSERT_EQ(ans, 2);

  for (uint64_t i = 0; i < 10; i++) {
    obj.AddElem("Andy");
    obj.AddElem("Connor");
    obj.AddElem("J-How");
    obj.AddElem("Kunle");
    obj.AddElem("Lan");
    obj.AddElem("Prashanth");
    obj.AddElem("William");
    obj.AddElem("Yash");
    obj.AddElem("Yuanxin");
    if (i == 0) {
      obj.ComputeCardinality();
      ans = obj.GetCardinality();
      ASSERT_EQ(ans, 6);
    }
  }

  obj.ComputeCardinality();
  ans = obj.GetCardinality();
  ASSERT_EQ(ans, 6);
}

TEST(HyperLogLogTest, DISABLED_BasicTest2) {
  auto obj = HyperLogLog<int64_t>(static_cast<int16_t>(3));

  ASSERT_EQ(obj.GetCardinality(), 0);

  obj.AddElem(0);

  obj.ComputeCardinality();
  auto ans = obj.GetCardinality();

  ASSERT_EQ(ans, 7);

  for (uint64_t i = 0; i < 10; i++) {
    obj.AddElem(10);
    obj.AddElem(122);
    obj.AddElem(200);
    obj.AddElem(911);
    obj.AddElem(999);
    obj.AddElem(1402);
    obj.AddElem(15445);
    obj.AddElem(15645);
    obj.AddElem(123456);
    obj.AddElem(312457);
    if (i == 0) {
      obj.ComputeCardinality();
      ans = obj.GetCardinality();
      ASSERT_EQ(ans, 10);
    }
  }

  for (uint64_t i = 0; i < 10; i++) {
    obj.AddElem(-1);
    obj.AddElem(-2);
    obj.AddElem(-3);
    obj.AddElem(-4);
    obj.AddElem(-5);
    obj.AddElem(-6);
    obj.AddElem(-7);
    obj.AddElem(-8);
